assignments.value:
=A new real estate lead just came in. Draft two short personalized responses for the agent to send.

AGENT: {{ $json.agent_name }}
LEAD NAME: {{ $json.payload.lead_name }}
LEAD SOURCE: {{ $json.payload.source }}
PROPERTY: {{ $json.payload.property_address || 'not specified' }}
PRICE RANGE: {{ $json.payload.price_range || 'not specified' }}
BEDS: {{ $json.payload.beds || 'not specified' }}
LEAD MESSAGE: {{ $json.payload.lead_message || 'No message provided' }}

Write two responses — a SHORT SMS (under 155 characters, conversational) and an EMAIL (2–3 sentences, warm). Both should:
- Address the lead by first name
- If PROPERTY is a real address, reference it specifically
- If PROPERTY is "not specified", keep it warm and general — express enthusiasm about helping them find the right home; do NOT invent or reference a property
- The primary goal is to prompt the lead to call the agent directly
- Sign off with the agent name

Format your response EXACTLY like this:
SMS: [your sms text here]
EMAIL: [your email text here]

parameters.jsCode:
const response = $input.first().json;
const text = response.content[0].text.trim();
const prev = $('Build Prompt').first().json;

// Parse SMS: and EMAIL: labels
const smsMatch = text.match(/^SMS:\s*(.+?)(?=\nEMAIL:|$)/ms);
const emailMatch = text.match(/EMAIL:\s*(.+)$/ms);

const sms_draft = smsMatch ? smsMatch[1].trim() : text.split('\n')[0];
const email_draft = emailMatch ? emailMatch[1].trim() : text;

// Generate session token
const token = crypto.randomUUID();

// Token expires in 24 hours
const expires = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();

const esc = v => (v || '').replace(/'/g, "''");

return [{
  json: {
    sms_draft,
    email_draft,
    token,
    expires,
    insert_query: `INSERT INTO approval_tokens (token, lead_id, client_id, sms_draft, email_draft, expires_at) VALUES ('${token}', '${prev.lead_id}', '${prev.client_id}', '${esc(sms_draft)}', '${esc(email_draft)}', '${expires}')`,
    lead_id: prev.lead_id,
    client_id: prev.client_id,
    agent_email: prev.agent_email,
    agent_name: prev.agent_name,
    lead_name: prev.lead_name,
    lead_phone: prev.lead_phone,
    lead_email: prev.lead_email,
    source: prev.source,
    lead_message: prev.lead_message
  }
}];

const ctx = $('Parse Drafts + Generate Token').first().json;
const base = 'https://norrai.app.n8n.cloud/webhook/lead-action';
const editBase = 'https://tools.norrai.co/lead_action_edit.html';
const t = encodeURIComponent(ctx.token);
const smsDraft = encodeURIComponent(ctx.sms_draft);
const emailDraft = encodeURIComponent(ctx.email_draft);
const leadName = encodeURIComponent(ctx.lead_name);

const sendSmsUrl = `${base}?token=${t}&action=send_sms`;
const sendEmailUrl = `${base}?token=${t}&action=send_email`;
const skipUrl = `${base}?token=${t}&action=skip`;
const editSmsUrl = `${editBase}?token=${t}&action=send_sms&draft=${smsDraft}&lead_name=${leadName}`;
const editEmailUrl = `${editBase}?token=${t}&action=send_email&draft=${emailDraft}&lead_name=${leadName}`;

const sourceLabel = (ctx.source || 'unknown').replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;background:#FAFAF7">
<h2 style="color:#0A0F1A">New lead from ${sourceLabel}</h2>
<p style="color:#3A3F48"><strong>${ctx.lead_name}</strong> reached out${ctx.lead_message ? ':' : '.'}</p>
${ctx.lead_message ? `<blockquote style="border-left:3px solid #7FA9B8;padding:8px 16px;color:#6A6F78;margin:16px 0">${ctx.lead_message}</blockquote>` : ''}
<hr style="border:1px solid #E5E4DE;margin:24px 0">
<h3 style="color:#0A0F1A">SMS Draft <span style="font-size:12px;color:#9EA3AA">(${ctx.sms_draft.length} chars)</span></h3>
<div style="background:#fff;border:1px solid #E5E4DE;border-radius:6px;padding:16px;margin-bottom:12px">
<p style="color:#0A0F1A;margin:0">${ctx.sms_draft}</p>
</div>
<table><tr>
<td><a href="${sendSmsUrl}" style="background:#0A0F1A;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">Send SMS</a></td>
<td style="padding-left:8px"><a href="${editSmsUrl}" style="background:#fff;color:#0A0F1A;padding:10px 20px;text-decoration:none;border-radius:4px;border:1px solid #E5E4DE;display:inline-block">Edit</a></td>
</tr></table>
<br>
<h3 style="color:#0A0F1A">Email Draft</h3>
<div style="background:#fff;border:1px solid #E5E4DE;border-radius:6px;padding:16px;margin-bottom:12px">
<p style="color:#0A0F1A;margin:0">${ctx.email_draft}</p>
</div>
<table><tr>
<td><a href="${sendEmailUrl}" style="background:#0A0F1A;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">Send Email</a></td>
<td style="padding-left:8px"><a href="${editEmailUrl}" style="background:#fff;color:#0A0F1A;padding:10px 20px;text-decoration:none;border-radius:4px;border:1px solid #E5E4DE;display:inline-block">Edit</a></td>
</tr></table>
<br>
<a href="${skipUrl}" style="color:#9EA3AA;font-size:13px">Skip this lead for now</a>
<hr style="border:1px solid #E5E4DE;margin:24px 0">
<p style="font-size:11px;color:#9EA3AA">These links expire in 24 hours. Norr AI</p>
</body></html>`;

return [{ json: { html, agent_email: ctx.agent_email, agent_name: ctx.agent_name, lead_name: ctx.lead_name, source_label: sourceLabel } }];

